function t(k){var L=I18N[lang]||I18N.en;return (L[k]!=null?L[k]:(I18N.en[k]||k));}
function applyLang(){document.querySelectorAll('[data-i18n]').forEach(function(e){e.textContent=t(e.getAttribute('data-i18n'));});document.querySelectorAll('[data-i18n-ph]').forEach(function(e){e.setAttribute('placeholder',t(e.getAttribute('data-i18n-ph')));});document.querySelectorAll('.nav-i[data-v],.mnav [data-v]').forEach(function(b){var k='nav_'+b.dataset.v,n=b.childNodes;for(var i=n.length-1;i>=0;i--){if(n[i].nodeType===3){n[i].textContent=t(k);break;}}});var nl=document.querySelector('#home .hero .label');if(nl&&nl.childNodes[0]&&nl.childNodes[0].nodeType===3)nl.childNodes[0].nodeValue=t('networth')+' · ';var ls=document.getElementById('langSel');if(ls)ls.value=lang;document.documentElement.lang=lang;}
