 if(/apotek|pharmacy|klinik|clinic|hospital|rumah sakit|kimia farma|guardian|watson|century|dokter|halodoc|alodokter|\bgym\b|fitness|bpjs|\blab\b/.test(m))return'Health';
 if(/cinema|cinepolis|\bcgv\b|\bxxi\b|karaoke|steam|playstation|nintendo|\bgame\b|nonton|tix ?id/.test(m))return'Entertainment';
 if(/google|netflix|spotify|youtube|disney|\bhbo\b|\bxl\b|telkom|telkomsel|indihome|\bpln\b|pdam|listrik|pulsa|internet|asuransi|insurance|subscription|adobe|microsoft|icloud|apple\.com|canva|openai|chatgpt|\bone\b|\bbill\b|subs/.test(m))return'Bills & Subs';
