function renderInsights(tx,income30){var st=document.getElementById('insStats'),tm=document.getElementById('topMerch');if(!st)return;if(!tx||!tx.length){st.innerHTML='<div class="empty" style="grid-column:1/-1">'+t('empty_spend')+'</div>';if(tm)tm.innerHTML='';return;}var total=tx.reduce(function(s,r){return s+txIDR(r);},0);var minTs=tx.reduce(function(m,r){return Math.min(m,r.ts||Date.now());},Date.now());var ddays=Math.max(1,Math.min(30,Math.round((Date.now()-minTs)/864e5)+1));var daily=total/ddays;var big=tx.reduce(function(m,r){return Math.abs(txIDR(r))>Math.abs(txIDR(m))?r:m;},tx[0]);var nw2=new Date(),dim=new Date(nw2.getFullYear(),nw2.getMonth()+1,0).getDate(),dom=nw2.getDate(),ym=nw2.toISOString().slice(0,7);var msp=tx.reduce(function(s,r){return (r.date||'').slice(0,7)===ym?s+Math.abs(txIDR(r)):s;},0);var proj=dom>0?Math.round(msp/dom*dim):Math.abs(total);var tiles=[[t('ins_spent'),'−'+idr(total)],[t('ins_daily'),idr(daily)],[t('ins_biggest'),idr(Math.abs(txIDR(big)))],[t('ins_txns'),String(tx.length)],[t('projected'),'−'+idr(proj)]];var srate=(income30>0)?Math.round((income30-Math.abs(total))/income30*100):null;if(srate!=null)tiles.push([t('savings_rate'),srate+'%']);st.innerHTML=tiles.map(function(x){return '<div class="stat"><span>'+x[0]+'</span><b>'+mask(x[1])+'</b></div>';}).join('');var by={};tx.forEach(function(z){var k=dispMerchant(z)||'Other';by[k]=(by[k]||0)+Math.abs(txIDR(z));});var top=Object.entries(by).sort(function(a,b){return b[1]-a[1];}).slice(0,5);var mx=top.length?top[0][1]:1;tm.innerHTML='<div class="sub2" style="margin:2px 0 10px">'+t('top_spending')+'</div>'+top.map(function(e){return '<div class="ibar"><div class="l" style="gap:10px"><span class="nm" style="font-weight:600;font-size:13px;flex:1 1 auto">'+esc(e[0])+'</span><span class="pct" style="flex:0 0 auto">'+mask(idr(e[1]))+'</span></div><div class="barwrap" style="height:7px"><i style="width:'+Math.max(5,Math.round(e[1]/mx*100))+'%;background:linear-gradient(90deg,#16C7A8,#2F86D6,#16336E)"></i></div></div>';}).join('');}
function renderBudgets(){var el=document.getElementById('budList');if(!el)return;var per=budgets.period||'monthly';var days=per==='weekly'?7:30;var cut=Date.now()-days*864e5;var sp=(DATA._tx||[]).filter(function(z){return (z.class==='spend'||z.class==='fee')&&(z.ts||new Date(z.date).getTime()||0)>=cut;});var byc={};sp.forEach(function(z){byc[z.c]=(byc[z.c]||0)+Math.abs(txIDR(z));});var tot=sp.reduce(function(s,z){return s+Math.abs(txIDR(z));},0);var over=[];function bar(label,spent,bud){var w=Math.max(3,Math.round(spent/bud*100));var ov=spent>bud;if(ov)over.push(label);var col=ov?'var(--red)':(spent>bud*0.85?'var(--gold)':'var(--green)');var rem=bud-spent;var note=ov?(t('over_budget')+' '+mask(idr(-rem))):(mask(idr(rem))+' '+t('remaining'));return '<div class="ibar"><div class="l"><span>'+label+'</span><span class="pct">'+mask(idr(spent))+' / '+mask(idr(bud))+'</span></div><div class="barwrap"><i style="width:'+Math.min(100,w)+'%;background:'+col+'"></i></div><div style="font-size:11px;margin-top:5px;color:'+(ov?'var(--red)':'var(--muted)')+'">'+note+'</div></div>';}var rows=[];if(budgets.overall>0)rows.push(bar(t('overall'),tot,budgets.overall));CATS.forEach(function(c){if(budgets.cats&&budgets.cats[c]>0)rows.push(bar(c,byc[c]||0,budgets.cats[c]));});var banner=over.length?'<div style="background:#FDECEF;color:var(--red);font-size:12px;font-weight:700;padding:10px 12px;border-radius:12px;margin-bottom:12px">⚠ '+t('over_budget_on')+' '+over.join(', ')+'</div>':'';el.innerHTML=rows.length?(banner+rows.join('')):'<div class="empty" style="padding:16px">'+t('no_budget')+'</div>';}
