function uploadStmt(){var f=document.getElementById('f_pdf').files[0];if(!f){alert('Choose a PDF first.');return;}var pw=document.getElementById('f_upw').value;var b=document.getElementById('upBtn');b.textContent='Reading...';b.disabled=true;var r=new FileReader();r.onload=function(){fetch('/api/upload',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({pdf:r.result,password:pw})}).then(function(x){return x.json();}).then(function(j){if(j&&j.ok&&j.accounts&&j.accounts.length){j.accounts.forEach(function(a){var key=a.acctNo||((a.institution||'')+'|'+(a.name||''));var ix=uploadedAccounts.findIndex(function(x){return (x.acctNo||((x.institution||'')+'|'+(x.name||'')))===key;});if(ix>=0){var old=uploadedAccounts[ix];a.uid=old.uid;var seen={},merged=[];(old.txns||[]).concat(a.txns||[]).forEach(function(tt){var ik=(tt.date||'')+'|'+(tt.desc||'')+'|'+(tt.amount||0);if(!seen[ik]){seen[ik]=1;merged.push(tt);}});if(merged.length)a.txns=merged;if(stmtAsof(old)>stmtAsof(a)){a.balance=old.balance;a.period=old.period||a.period;}uploadedAccounts[ix]=a;}else{a.uid='u'+Date.now().toString(36)+Math.random().toString(36).slice(2,6);uploadedAccounts.push(a);}});try{localStorage.setItem('cr_uploads',JSON.stringify(uploadedAccounts));}catch(e){}closeForm();paint();show('accounts');}else{b.textContent='Read & add';b.disabled=false;alert(j&&j.error==='wrong_or_missing_password'?'Wrong or missing PDF password.':(j&&j.note==='no_text')?'This PDF has no readable text. It may be a scanned image, so please add the balance manually with + Add account.':(j&&j.note==='no_balance_found')?'Could not find a balance in that statement. Please add it manually with + Add account.':'Could not read that PDF.');}}).catch(function(){b.textContent='Read & add';b.disabled=false;alert('Upload failed.');});};r.onerror=function(){b.textContent='Read & add';b.disabled=false;alert('Could not read the file.');};r.readAsDataURL(f);}
function dispMerchant(r){var raw=(r.merchant||'').trim(),cl=r.class||'spend';if(cl==='transfer_in')return /bi.?fast|remit/i.test(raw)?'Incoming BI-FAST':'Incoming transfer';if(cl==='transfer')return /bi.?fast/i.test(raw)?'Transfer · BI-FAST':'Transfer';if(cl==='card_payment')return 'Card payment';if(cl==='topup')return (raw&&raw.length<=30)?cleanDesc(raw):'Top-up';var m=cleanDesc(raw);return m||'Transaction';}
