const fmtD=s=>{if(s==null||s==='')return '';const m=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];const d=new Date(s);if(isNaN(d.getTime()))return '';return d.getDate()+' '+m[d.getMonth()];};
function insWin(){var now=Date.now();if(insRange==='month'){var d=new Date();return [new Date(d.getFullYear(),d.getMonth(),1).getTime(),now];}if(insRange==='custom'){var f=insFrom?new Date(insFrom+'T00:00:00').getTime():(now-2592e6);var ti=insTo?new Date(insTo+'T23:59:59').getTime():now;if(f>ti){var z=f;f=ti;ti=z;}return [f,ti];}return [now-2592e6,now];}function syncInsRange(){var lbl=insRange==='month'?t('rg_month'):(insRange==='custom'?t('rg_custom'):t('rg_last30'));var wg=document.getElementById('wgTitle');if(wg)wg.textContent=t('where_goes_b')+' · '+lbl;var it2=document.getElementById('insTitle');if(it2)it2.textContent=t('insights_b')+' · '+lbl;var sel=document.getElementById('insRange');if(sel&&sel.value!==insRange)sel.value=insRange;var cc=document.getElementById('insCustom');if(cc)cc.style.display=insRange==='custom'?'flex':'none';var f=document.getElementById('insFrom');if(f&&insFrom)f.value=insFrom;var tt=document.getElementById('insTo');if(tt&&insTo)tt.value=insTo;}function cats(id,tx){const by={};tx.forEach(t=>by[t.c]=(by[t.c]||0)-txIDR(t));const tot=Object.values(by).reduce((a,b)=>a+b,0)||1;document.getElementById(id).innerHTML=Object.entries(by).sort((a,b)=>b[1]-a[1]).map(([c,v])=>`<div class="ibar" data-act="catTx" data-arg="${encodeURIComponent(c)}" style="cursor:pointer"><div class="l"><span>${esc(c)}</span><span class="pct">${Math.round(v/tot*100)}% · ${idr(v)}</span></div><div class="barwrap"><i style="width:${Math.max(4,Math.round(v/tot*100))}%;background:${CATCOL[c]||'#8AA0C6'}"></i></div></div>`).join('');}
