(function(){var y0=0,curDy=0,drag=false,active=false,SH=null,SC=null;function scAnc(el,root){while(el&&el!==root.parentNode){try{if(el.scrollHeight>el.clientHeight+2){var ov=getComputedStyle(el).overflowY;if(ov==='auto'||ov==='scroll')return el;}}catch(_){}el=el.parentElement;}return null;}document.addEventListener('touchstart',function(e){var sh=document.getElementById('sheet');if(!sh||!sh.classList.contains('show')||window.innerWidth>=900)return;if(!sh.contains(e.target))return;SH=sh;SC=scAnc(e.target,sh);y0=e.touches[0].clientY;curDy=0;drag=false;active=true;},{passive:true});document.addEventListener('touchmove',function(e){if(!active||!SH)return;var dy=e.touches[0].clientY-y0;if(!drag){if(dy>6&&(!SC||SC.scrollTop<=0)){drag=true;SH.style.transition='none';}else{if(dy<-2||(SC&&SC.scrollTop>0))active=false;return;}}if(dy<0)dy=0;curDy=dy;SH.style.transform='translateY('+dy+'px)';e.preventDefault();},{passive:false});function end(){if(!SH)return;var sh=SH,d=drag,dy=curDy;SH=null;SC=null;active=false;drag=false;curDy=0;sh.style.transition='';if(d&&dy>90){var bd=document.getElementById('bd');if(bd)bd.classList.remove('show');sh.style.transform='translateY(110%)';setTimeout(function(){closeForm();sh.style.transform='';},300);}else{sh.style.transform='';}}document.addEventListener('touchend',end);document.addEventListener('touchcancel',end);})();

function pfSVG(pts,cost){var W=400,H=210,L=10,R=10,T=14,B=22,iw=W-L-R,ih=H-T-B;var vals=pts.map(function(p){return p.v;});if(cost>0)vals.push(cost);if(!vals.length)vals=[0,1];var mn=Math.min.apply(null,vals),mx=Math.max.apply(null,vals);if(mn===mx){mn=mn*0.97;mx=mx*1.03||1;}function X(i){return pts.length<=1?L+iw/2:L+iw*i/(pts.length-1);}function Y(v){return T+ih*(1-(v-mn)/(mx-mn));}var col=(pts.length>1&&pts[pts.length-1].v>=pts[0].v)?'#13B97A':(pts.length>1?'#F0476A':'#16336E');var s='<svg viewBox="0 0 '+W+' '+H+'" style="width:100%;height:auto;display:block">';s+='<defs><linearGradient id="pfg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="'+col+'" stop-opacity=".22"/><stop offset="1" stop-color="'+col+'" stop-opacity="0"/></linearGradient></defs>';if(pts.length>1){var area='M'+X(0).toFixed(1)+','+Y(pts[0].v).toFixed(1);pts.forEach(function(p,i){area+='L'+X(i).toFixed(1)+','+Y(p.v).toFixed(1);});area+='L'+X(pts.length-1).toFixed(1)+','+(T+ih)+'L'+X(0).toFixed(1)+','+(T+ih)+'Z';s+='<path d="'+area+'" fill="url(#pfg)"/>';}if(cost>0){var cy=Y(cost).toFixed(1);s+='<line x1="'+L+'" y1="'+cy+'" x2="'+(W-R)+'" y2="'+cy+'" stroke="#9AA8C7" stroke-width="1" stroke-dasharray="4 4"/><text x="'+(W-R)+'" y="'+(Y(cost)-4).toFixed(1)+'" text-anchor="end" font-size="10" fill="#6B7A99">'+t('cost_basis')+'</text>';}if(pts.length>1){var pl=pts.map(function(p,i){return X(i).toFixed(1)+','+Y(p.v).toFixed(1);}).join(' ');s+='<polyline points="'+pl+'" fill="none" stroke="'+col+'" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>';}if(pts.length){s+='<circle cx="'+X(pts.length-1).toFixed(1)+'" cy="'+Y(pts[pts.length-1].v).toFixed(1)+'" r="3.5" fill="'+col+'"/>';}s+='</svg>';return s;}
function openStock(i){var h=holdings[i];if(!h)return;openSheet('<h3>'+esc(h.name||h.symbol)+'</h3><div class="d">Loading chart…</div>');fetch('/api/yf?range=6mo&symbol='+encodeURIComponent(h.symbol)).then(function(r){return r.json();}).then(function(d){var hist=(d.history||[]).map(function(p){return {v:p[1]};});var price=d.price||h.price||0;var ccy=d.currency||h.ccy||'USD';var val=(+h.units||0)*price;var gp=h.avg?((price/h.avg-1)*100):0;var cls=gp>=0?'pos':'neg';var ysym=d.symbol||h.symbol;var html='<h3 style="display:flex;justify-content:space-between;align-items:center;gap:10px"><span>'+esc(h.name||h.symbol)+'</span><span class="'+cls+'" style="font-size:14px;font-weight:800">'+(gp>=0?'+':'')+gp.toFixed(1)+'%</span></h3>'+'<div class="d" style="margin:-8px 0 10px">'+esc(h.symbol+(d.exch?(' · '+d.exch):'')+' · '+fmt(price,ccy))+'</div>'+(hist.length>1?pfSVG(hist,+h.avg||0):'<div class="empty">No chart data available</div>')+'<div style="display:flex;justify-content:space-between;margin-top:10px"><div><div class="d">'+t('current_value')+'</div><div style="font-weight:800;font-size:17px">'+mask(fmt(val,ccy))+'</div></div><div style="text-align:right"><div class="d">'+t('cost_basis')+'</div><div style="font-weight:700">'+esc(h.units+' @ '+fmt(h.avg,ccy))+'</div></div></div>'+'<a class="btn ghost" style="display:block;text-align:center;margin-top:12px;text-decoration:none" href="https://finance.yahoo.com/quote/'+encodeURIComponent(ysym)+'" target="_blank" rel="noopener">'+t('view_yahoo')+'</a>';openSheet(html);}).catch(function(){openSheet('<h3>'+esc(h.name||h.symbol)+'</h3><div class="empty">Could not load chart.</div><a class="btn ghost" style="display:block;text-align:center;margin-top:12px;text-decoration:none" href="https://finance.yahoo.com/quote/'+encodeURIComponent(h.symbol)+'" target="_blank" rel="noopener">'+t('view_yahoo')+'</a>');});}
var selStock=null,yfSug=[],yfT;
function yfDeb(){clearTimeout(yfT);yfT=setTimeout(yfSearch,260);}
function yfSearch(){var el=document.getElementById('f_q');if(!el)return;var q=el.value.trim();var box=document.getElementById('f_sug');if(!box)return;if(q.length<2){box.innerHTML='';return;}fetch('/api/yf?q='+encodeURIComponent(q)).then(function(r){return r.json();}).then(function(d){yfSug=(d.quotes||[]);if(!yfSug.length){box.innerHTML='<div class="d" style="padding:6px 2px">No matches</div>';return;}box.innerHTML=yfSug.map(function(s,i){return '<div class="row2" data-act="pickStock" data-arg="'+i+'" style="cursor:pointer;padding:10px 0"><div class="l"><div><div class="nm">'+esc(s.symbol)+' <span class="d" style="font-weight:600">'+esc(s.exch||'')+'</span></div><div class="d">'+esc(s.name||'')+'</div></div></div></div>';}).join('');}).catch(function(){box.innerHTML='';});}
function pickStock(i){var s=yfSug[i];if(!s)return;document.getElementById('f_sug').innerHTML='';document.getElementById('f_q').value=s.symbol;selStock={symbol:s.symbol,name:s.name,exch:s.exch,ccy:'USD',price:0};var pk=document.getElementById('f_pick');pk.innerHTML='<div class="d" style="margin:2px 0 8px">Loading '+esc(s.symbol)+'…</div>';fetch('/api/yf?range=1d&symbol='+encodeURIComponent(s.symbol)).then(function(r){return r.json();}).then(function(d){if(d&&d.price){selStock.price=d.price;selStock.ccy=d.currency||'USD';if(d.name)selStock.name=d.name;if(d.exch)selStock.exch=d.exch;}var lbl=document.getElementById('f_avglbl');if(lbl)lbl.textContent='Avg buy price ('+selStock.ccy+')';pk.innerHTML='<div class="card" style="margin:2px 0 10px;padding:12px 14px"><div style="font-weight:700">'+esc(selStock.name||selStock.symbol)+'</div><div class="d">'+esc(selStock.symbol+(selStock.exch?(' · '+selStock.exch):''))+'</div><div style="margin-top:6px;font-weight:800">'+esc(fmt(selStock.price,selStock.ccy))+' <span class="d" style="font-weight:600">current price</span></div></div>';}).catch(function(){pk.innerHTML='<div class="d">Could not load price; you can still save.</div>';});}
function refreshPrices(){if(!holdings.length)return;Promise.all(holdings.map(function(h){if(!h.symbol)return null;return fetch('/api/yf?range=1d&symbol='+encodeURIComponent(h.symbol)).then(function(r){return r.json();}).then(function(d){if(d&&d.price){h.price=d.price;if(d.currency)h.ccy=d.currency;if(d.exch&&!h.exch)h.exch=d.exch;if(d.name&&(!h.name||h.name===h.symbol))h.name=d.name;}}).catch(function(){});})).then(function(){save();paint();}).catch(function(){});}
function addAccount(){const n=document.getElementById('f_name').value.trim();if(!n)return;accounts.push({type:document.getElementById('f_type').value,name:n,bal:numVal('f_bal'),ccy:document.getElementById('f_ccy').value});save();closeForm();paint();show('accounts');}
function addHolding(){var units=+(document.getElementById('f_units').value)||0;var avg=numVal('f_avg');function commit(st){if(!st||!st.symbol){var q=document.getElementById('f_q');if(q)q.focus();return;}holdings.push({symbol:st.symbol,name:st.name||st.symbol,exch:st.exch||'',units:units,avg:avg,price:+st.price||0,ccy:st.ccy||'USD'});save();selStock=null;closeForm();paint();show('portfolio');}if(selStock&&selStock.symbol)return commit(selStock);var q=(document.getElementById('f_q').value||'').trim();if(!q)return;fetch('/api/yf?range=1d&symbol='+encodeURIComponent(q.toUpperCase())).then(function(r){return r.json();}).then(function(d){if(d&&d.price)commit({symbol:d.symbol||q.toUpperCase(),name:d.name,exch:d.exch,ccy:d.currency||'USD',price:d.price});else commit({symbol:q.toUpperCase(),name:q.toUpperCase(),ccy:mainCcy,price:0});}).catch(function(){commit({symbol:q.toUpperCase(),name:q.toUpperCase(),ccy:mainCcy,price:0});});}
function discoverStmtBanks(){
  var sel=document.getElementById('f_bank'); if(!sel) return;
  fetch('/api/statements?discover=1').then(function(r){return r.json();}).then(function(j){
    var banks=(j&&j.banks)||[];
    if(!banks.length){ sel.innerHTML='<option value="">'+t('stmt_none')+'</option>'; sel.disabled=true; return; }
    sel.disabled=false; sel.innerHTML=banks.map(function(b){return '<option value="'+esc(b.key)+'">'+esc(b.institution||b.key)+'</option>';}).join('');
  }).catch(function(){ sel.innerHTML='<option value="">'+t('stmt_err')+'</option>'; sel.disabled=true; });
}
function saveStmt(){var bank=document.getElementById('f_bank').value,pw=document.getElementById('f_pw').value;if(!bank||!pw)return;fetch('/api/unlock',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({bank:bank,password:pw})}).then(r=>r.json()).then(()=>{document.getElementById('stmtSub').textContent='Saved — reading statements…';closeForm();readStmt();}).catch(()=>closeForm());}
function numVal(id){var e=document.getElementById(id);return e?(parseFloat(String(e.value).replace(/,/g,''))||0):0;}
function groupNum(el){var raw=String(el.value).replace(/[^\d.,]/g,'');var lastSep=Math.max(raw.lastIndexOf('.'),raw.lastIndexOf(','));var intPart,decPart='',trail=false;if(lastSep>=0){var after=raw.length-lastSep-1;if(after>=1&&after<=2){intPart=raw.slice(0,lastSep).replace(/[.,]/g,'');decPart=raw.slice(lastSep+1).replace(/[^\d]/g,'');}else if(after===0){intPart=raw.replace(/[.,]/g,'');trail=true;}else{intPart=raw.replace(/[.,]/g,'');}}else{intPart=raw;}intPart=intPart.replace(/^0+(?=\d)/,'');var g=intPart.replace(/\B(?=(\d{3})+(?!\d))/g,',');el.value=decPart!==''?g+'.'+decPart:(trail?g+'.':g);}
function openStmtTxns(uid){var a=mergeStmtAccounts().find(function(x){return x.uid===uid;});if(!a)return;if(!a.txns||!a.txns.length){openSheet('<h3>'+esc(a.name)+'</h3><div class="d" style="margin:2px 0 12px">'+esc((a.institution||'')+' · '+fmt(a.balance,a.ccy||'IDR'))+'</div><div class="empty">'+(lang==='id'?'Belum ada rincian transaksi. Unggah ulang atau sinkronkan statement ini.':'No transaction detail yet. Re-upload or re-sync this statement to see the breakdown.')+'</div>');return;}var cv=function(n){return mask(fmt(conv(Math.abs(n),a.ccy||'IDR'),mainCcy));};var sp=0,inc=0;a.txns.forEach(function(t){if(t.amount<0)sp+=t.amount;else inc+=t.amount;});var rows=a.txns.map(function(t){var cls=t.amount<0?'neg':'pos';return '<div class="row2"><div class="l"><div style="min-width:0"><div class="nm" style="font-size:13px">'+esc(cleanDesc(t.desc))+'</div><div class="d">'+esc(t.date)+'</div></div></div><div class="amt '+cls+'">'+(t.amount<0?'-':'+')+cv(t.amount)+'</div><button class="del" data-act="hideTx" data-arg="'+encodeURIComponent((a.uid||'')+'|'+(t.date||'')+'|'+(t.desc||'')+'|'+Math.round(+t.amount||0))+'">×</button></div>';}).join('');var html='<h3 style="display:flex;justify-content:space-between;align-items:center"><span>'+esc(a.name)+'</span><span class="d" style="font-weight:600">'+(a.period?esc(a.period):'')+'</span></h3><div style="display:flex;gap:10px;margin:2px 0 12px"><div class="stat" style="flex:1"><div class="d">Money out</div><div class="neg" style="font-weight:800;font-size:15px">'+cv(sp)+'</div></div><div class="stat" style="flex:1"><div class="d">Money in</div><div class="pos" style="font-weight:800;font-size:15px">'+cv(inc)+'</div></div></div><div style="max-height:44vh;overflow:auto;margin:0 -2px">'+rows+'</div>';openSheet(html);}
function stmtTs(d,yr){var m=String(d||'').match(/(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?/);if(!m)return Date.now();var y=m[3]?(+m[3]<100?2000+(+m[3]):+m[3]):(+yr||new Date().getFullYear());return new Date(y,(+m[2]||1)-1,+m[1]||1).getTime();}
function stmtTxFeed(){try{var out=[];mergeStmtAccounts().forEach(function(a){if(!a||!a.txns||!a.txns.length)return;var pyrs=(a.period&&a.period.match(/20\d{2}/g))||[];var y0=pyrs.length?+pyrs[0]:0,y1=pyrs.length?+pyrs[pyrs.length-1]:0;function ry(ds){var mm=String(ds||'').match(/\d{1,2}[\/-](\d{1,2})/);mm=mm?+mm[1]:0;if(y0&&y1&&y1>y0)return mm===12?y0:y1;return y0||new Date().getFullYear();}var rate=(a.ccy&&a.ccy!=='IDR'&&FX['IDR']&&FX[a.ccy])?(FX['IDR']/FX[a.ccy]):1;a.txns.forEach(function(tt){var neg=(+tt.amount||0)<0;var desc=tt.desc||'';var low=desc.toLowerCase();var ccPay=((/bill\s*payment|billpayment|pembayaran|payment/.test(low))&&/ccard|credit\s*card|kartu\s*kredit|\bc card\b|\bcc\b/.test(low))||(a.type==='credit_card'&&!neg&&/payment|pembayaran|thank|terima kasih/.test(low));var cls=ccPay?'card_payment':(/\b(trf|transfer|bifast|rtgs|skn|kliring|pemindahan|setoran|tarik tunai|withdrawal)\b/i.test(desc)?(neg?'transfer_out':'transfer_in'):(/biaya|admin|adm\.|\bfee\b|charge|pajak|materai/i.test(desc)?'fee':(neg?'spend':'income')));out.push({merchant:desc||'Transaction',amount:(a.ccy&&a.ccy!=='IDR')?(+tt.amount||0)*rate:(+tt.amount||0),ccy:'IDR',ts:stmtTs(tt.date,ry(tt.date)),date:new Date(stmtTs(tt.date,ry(tt.date))||Date.now()).toISOString().slice(0,10),account:a.name,class:cls,c:cat(desc),source:'statement'});});});return out;}catch(e){return [];}}
