function exportCSV(){var tx=DATA._tx||[];if(!tx.length){alert(t('no_data'));return;}var rows=[['Date','Merchant','Account','Type','Category','Amount']].concat(tx.map(function(x){return [x.date,'"'+String(x.merchant||'').replace(/"/g,'""')+'"',x.account||'',x.class||'',x.c||'',x.amount];}));var csv=rows.map(function(r){return r.join(',');}).join('\n');var b=new Blob([csv],{type:'text/csv'});var u=URL.createObjectURL(b);var a=document.createElement('a');a.href=u;a.download='crumina-transactions.csv';document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(u);}
function renderGoals(){var el=document.getElementById('goalList');if(!el)return;el.innerHTML=goals.length?goals.map(function(g,i){var saved=goalSaved(g);var pct=g.target>0?Math.min(100,Math.round(saved/g.target*100)):0;var reached=g.target>0&&saved>=g.target;var via=goalAcctLabel(g);return '<div class="ibar" data-act="editGoal" data-arg="'+i+'" style="cursor:pointer"><div class="l"><span>'+esc(g.name)+(reached?' <span style="color:#13B97A;font-weight:700">\u2713 '+t('g_reached')+'</span>':'')+'</span><span class="pct">'+mask(idr(saved))+' / '+mask(idr(g.target))+' · '+pct+'%</span></div><div class="barwrap"><i style="width:'+pct+'%;background:'+(reached?'#13B97A':'linear-gradient(90deg,#16C7A8,#13B97A)')+'"></i></div><div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px"><span class="d" style="font-size:11px">'+(via?t('g_via')+' '+esc(via):t('g_manual'))+'</span><button class="del" style="font-size:12px;color:var(--muted)" data-act="delGoal" data-arg="'+i+'">'+t('remove')+'</button></div></div>';}).join(''):'<div class="empty" style="padding:14px">'+t('no_goals')+'</div>';}
var _goalEdit=-1;
function toIDR(a,c){var m=conv(a,c||mainCcy);return (mainCcy==='IDR'||!FX['IDR'])?m:m*FX['IDR'];}
function txIDR(z){return toIDR(+(z&&z.amount)||0,(z&&z.ccy)||'IDR');}
function idrToMain(v){return (mainCcy==='IDR'||!FX['IDR'])?v:v/FX['IDR'];}
function linkableAccounts(){var out=[];try{mergeStmtAccounts().forEach(function(a){if(a&&!a.error&&a.uid&&a.type!=='credit_card')out.push({id:'s:'+a.uid,label:a.name||a.institution||'Account',bal:toIDR(a.balance||0,a.ccy||'IDR')});});}catch(e){}try{(accounts||[]).forEach(function(a){if(a&&a.name)out.push({id:'m:'+a.name,label:a.name,bal:toIDR(a.bal||0,a.ccy||mainCcy)});});}catch(e){}return out;}
function goalSaved(g){if(g&&g.acct){var L=linkableAccounts();for(var i=0;i<L.length;i++)if(L[i].id===g.acct)return L[i].bal;return g.saved||0;}return (g&&g.saved)||0;}
function goalAcctLabel(g){if(g&&g.acct){var L=linkableAccounts();for(var i=0;i<L.length;i++)if(L[i].id===g.acct)return L[i].label;}return '';}
function saveGoal(){var n=((document.getElementById('g_name')||{}).value||'').trim();var tg=+(document.getElementById('g_target')||{}).value||0;if(!n||!tg)return;var R=function(v){return mainCcy==='IDR'||!FX['IDR']?v:v*FX['IDR'];};var acct=(document.getElementById('g_acct')||{}).value||'';var sv=acct?0:(+(document.getElementById('g_saved')||{}).value||0);var obj={name:n,target:R(tg),acct:acct,saved:R(sv)};if(_goalEdit>=0&&goals[_goalEdit])goals[_goalEdit]=obj;else goals.push(obj);_goalEdit=-1;try{localStorage.setItem('cr_goals',JSON.stringify(goals));}catch(e){}closeForm();paint();}
function delGoal(i){goals.splice(i,1);try{localStorage.setItem('cr_goals',JSON.stringify(goals));}catch(e){}paint();}
function detectRecurring(tx){var sp=(tx||[]).filter(function(x){return x.class==='spend'||x.class==='fee';});var g={};sp.forEach(function(x){var k=mkey(dispMerchant(x));if(k)(g[k]=g[k]||[]).push(x);});var out=[];Object.keys(g).forEach(function(k){var arr=g[k];if(arr.length<2)return;arr.sort(function(a,b){return (a.ts||0)-(b.ts||0);});var amts=arr.map(function(x){return Math.abs(txIDR(x));}).slice().sort(function(a,b){return a-b;});var med=amts[Math.floor(amts.length/2)];if(!med)return;if(amts.filter(function(a){return Math.abs(a-med)<=med*0.25;}).length<2)return;var ivs=[];for(var i=1;i<arr.length;i++){var d=((arr[i].ts||0)-(arr[i-1].ts||0))/86400000;if(d>0)ivs.push(d);}if(!ivs.length)return;ivs.sort(function(a,b){return a-b;});var iv=ivs[Math.floor(ivs.length/2)];if(iv<5||iv>400)return;var last=arr[arr.length-1];var nx=new Date(last.ts||Date.now());nx.setDate(nx.getDate()+Math.round(iv));out.push({name:dispMerchant(last),amount:med,monthly:med*(30/iv),every:Math.round(iv),next:nx.toISOString().slice(0,10),cat:cat(last.merchant),conf:arr.length>=3});});out.sort(function(a,b){return ((b.conf?1:0)-(a.conf?1:0))||((b.monthly||0)-(a.monthly||0));});return out;}
function renderRecurring(tx){var el=document.getElementById('recurList');if(!el)return;var r=detectRecurring(tx);if(!r.length){el.innerHTML='<div class="empty" style="padding:14px">'+t('no_recurring')+'</div>';return;}var tot=r.reduce(function(s,x){return s+(x.monthly||x.amount);},0);var soon=Date.now()+7*864e5;el.innerHTML='<div class="sub2" style="margin-bottom:10px">'+t('monthly_est')+': '+mask(idr(tot))+'</div>'+r.slice(0,8).map(function(x){var due=new Date(x.next).getTime()<=soon;return '<div class="row2"><div class="l"><div class="ic" style="background:'+(CATCOL[x.cat]||'#8AA0C6')+'">'+esc((String(x.name||'?')[0]||'?').toUpperCase())+'</div><div><div class="nm">'+esc(x.name)+(x.conf?'':' <span style="font-size:10px;color:var(--muted);font-weight:600">('+t('ins_possible')+')</span>')+'</div><div class="d">'+t('next')+' '+fmtD(x.next)+' · ~'+x.every+'d'+(due?' · '+t('due_soon'):'')+'</div></div></div><div class="amt">'+mask(idr(x.amount))+'</div></div>';}).join('');}
function renderTrend(tx){var el=document.getElementById('trendList');if(!el)return;var sp=(tx||[]).filter(function(x){return x.class==='spend'||x.class==='fee';});var by={};sp.forEach(function(x){var dt=new Date(x.ts||x.date||0);if(isNaN(dt.getTime()))return;var k=dt.getFullYear()+'-'+('0'+(dt.getMonth()+1)).slice(-2);by[k]=(by[k]||0)+Math.abs(txIDR(x));});var keys=Object.keys(by).sort().slice(-6);if(!keys.length){el.innerHTML='<div class="empty" style="padding:14px">'+t('no_data')+'</div>';return;}var vals=keys.map(function(k){return by[k];});var mx=Math.max.apply(null,vals)||1;var MN=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];var W=600,H=180,pad=30,n=keys.length;var xs=keys.map(function(k,i){return n>1?pad+i*(W-2*pad)/(n-1):W/2;});var ys=vals.map(function(v){return (H-30)-(v/mx)*(H-54);});var line=xs.map(function(x,i){return (i?'L':'M')+x.toFixed(1)+' '+ys[i].toFixed(1);}).join(' ');var area=line+' L'+xs[n-1].toFixed(1)+' '+(H-30)+' L'+xs[0].toFixed(1)+' '+(H-30)+' Z';window._trend={keys:keys,vals:vals,xs:xs,ys:ys,MN:MN,W:W,H:H};var dots=xs.map(function(x,i){return '<circle cx="'+x.toFixed(1)+'" cy="'+ys[i].toFixed(1)+'" r="5" fill="#16336E" stroke="#fff" stroke-width="2.5"/>';}).join('');var hw=n>1?(W-2*pad)/(n-1):W;var hits=xs.map(function(x,i){return '<rect x="'+(x-hw/2).toFixed(1)+'" y="0" width="'+hw.toFixed(1)+'" height="'+H+'" fill="transparent" style="cursor:pointer" data-trend="'+i+'"/>';}).join('');var cym=new Date().toISOString().slice(0,7);var labels=keys.map(function(k,i){return '<text x="'+xs[i].toFixed(1)+'" y="'+(H-8)+'" text-anchor="middle" font-size="12" fill="#6B7A99">'+(MN[(+k.slice(5,7))-1]||'')+(k===cym?'*':'')+'</text>';}).join('');el.innerHTML='<div style="position:relative"><div id="trendTip" style="position:absolute;left:0;top:0;pointer-events:none;opacity:0;transform:translate(-50%,-135%);background:#0A1B3D;color:#fff;font-size:11.5px;font-weight:700;padding:6px 10px;border-radius:10px;white-space:nowrap;transition:opacity .15s ease;z-index:5;box-shadow:0 6px 16px -4px rgba(10,27,61,.4)"></div><svg viewBox="0 0 '+W+' '+H+'" width="100%" style="display:block;overflow:visible"><defs><linearGradient id="tg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#2F86D6" stop-opacity="0.35"/><stop offset="1" stop-color="#2F86D6" stop-opacity="0"/></linearGradient></defs><path d="'+area+'" fill="url(#tg)"/><path d="'+line+'" fill="none" stroke="#16336E" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>'+dots+labels+hits+'</svg></div>'+(keys.indexOf(new Date().toISOString().slice(0,7))>=0?'<div class="d" style="font-size:10px;margin-top:3px;text-align:right">'+t('ins_sofar')+'</div>':'');}
function trendShow(i){var T=window._trend;if(!T)return;var tip=document.getElementById('trendTip');if(!tip)return;tip.style.left=(T.xs[i]/T.W*100)+'%';tip.style.top=(T.ys[i]/T.H*100)+'%';tip.innerHTML=(T.MN[(+T.keys[i].slice(5,7))-1]||'')+' · '+mask(idr(T.vals[i]));tip.style.opacity='1';}
function trendHide(){var tip=document.getElementById('trendTip');if(tip)tip.style.opacity='0';}
function notify(title,body,tag){if(!('Notification'in window)||Notification.permission!=='granted')return;try{if(navigator.serviceWorker&&navigator.serviceWorker.ready){navigator.serviceWorker.ready.then(function(reg){reg.showNotification(title,{body:body,tag:tag,icon:'/icon-192.png',badge:'/icon-192.png'});});}else{new Notification(title,{body:body,icon:'/icon-192.png'});}}catch(e){}}
function updateNotifUI(){var e=document.getElementById('notifStatus');if(!e)return;e.textContent=(!('Notification'in window))?t('notif_unsupported'):({granted:t('notif_granted'),denied:t('notif_denied'),'default':t('notif_enable_hint')})[Notification.permission];}
function requestNotify(){if(!('Notification'in window)){alert(t('notif_unsupported'));return;}Notification.requestPermission().then(function(p){updateNotifUI();if(p==='granted'){notify('Crumina',t('notif_on_body'),'welcome');checkAlerts();}});}
function checkAlerts(){if(!('Notification'in window)||Notification.permission!=='granted')return;var today=new Date().toISOString().slice(0,10);var done=load('cr_notified',{});function fire(tag,title,body){if(done[tag]===today)return;done[tag]=today;notify(title,body,tag);}
var per=budgets.period||'monthly';var days=per==='weekly'?7:30;var cut=Date.now()-days*864e5;var sp=(DATA._tx||[]).filter(function(z){return (z.class==='spend'||z.class==='fee')&&(z.ts||new Date(z.date).getTime()||0)>=cut;});var byc={};sp.forEach(function(z){byc[z.c]=(byc[z.c]||0)+Math.abs(txIDR(z));});var tot=sp.reduce(function(s,z){return s+Math.abs(txIDR(z));},0);
if(budgets.overall>0&&tot>budgets.overall)fire('bud-all-'+per,t('notif_budget_title'),t('overall')+': '+idr(tot)+' / '+idr(budgets.overall));
if(budgets.cats)CATS.forEach(function(c){if(budgets.cats[c]>0&&(byc[c]||0)>budgets.cats[c])fire('bud-'+c,t('notif_budget_title'),c+': '+idr(byc[c])+' / '+idr(budgets.cats[c]));});
var soon=Date.now()+3*864e5;detectRecurring(DATA._tx||[]).forEach(function(x){var nd=new Date(x.next).getTime();if(nd<=soon&&nd>=Date.now()-864e5)fire('rec-'+mkey(x.name),t('notif_bill_title'),x.name+' ~'+idr(x.amount)+' '+t('due_soon'));});
try{localStorage.setItem('cr_notified',JSON.stringify(done));}catch(e){}}
function loadApp(){fetch('/api/data').then(r=>{if(r.status===401){location.href='/login';return null;}return r.json();}).then(d=>{if(!d)return;DATA.profile=d.profile||{};try{localStorage.setItem('cr_prof_cache',JSON.stringify(DATA.profile));}catch(e){}try{const c=localStorage.getItem('cr_data');if(c)DATA.data=JSON.parse(c);}catch(e){}loadFX(paint);});}
applyTheme();applyLang();updateEye();loadApp();refreshPrices();
